// Personal dot limits for ghost release
export const PERSONAL_DOT_LIMITS = {
	PINKY: (_level: number) => 0,
	INKY: (level: number) => (level === 1 ? 30 : 0),
	CLYDE: (level: number) => {
		if (level === 1) return 60
		if (level === 2) return 50
		return 0
	},
}

