// Pac-Man Game Types

// Direction enums (counter-clockwise order)
// NOTE: This order determines tie-breakers in shortest distance turn logic
// (higher priority turns have lower enum values)
export enum Direction {
	UP = 0,
	LEFT = 1,
	DOWN = 2,
	RIGHT = 3,
}

// Ghost modes representing current state
export enum GhostMode {
	OUTSIDE = 0,
	EATEN = 1,
	GOING_HOME = 2,
	ENTERING_HOME = 3,
	PACING_HOME = 4,
	LEAVING_HOME = 5,
}

// Ghost command modes (scatter vs chase)
export enum GhostCommand {
	CHASE = 0,
	SCATTER = 1,
}

// Ghost releaser counter modes
export enum ReleaserMode {
	PERSONAL = 0,
	GLOBAL = 1,
}

// Ghost names for indexing
export enum GhostName {
	BLINKY = 0,
	PINKY = 1,
	INKY = 2,
	CLYDE = 3,
}

// Speed control patterns
export enum SpeedPattern {
	PACMAN = 0,
	GHOST = 1,
	PACMAN_FRIGHT = 2,
	GHOST_FRIGHT = 3,
	GHOST_TUNNEL = 4,
	ELROY1 = 5,
	ELROY2 = 6,
}

// Game states
export enum GameState {
	READY = 'ready',
	PLAYING = 'playing',
	PAUSED = 'paused',
	DYING = 'dying',
	LEVEL_COMPLETE = 'level_complete',
	GAME_OVER = 'game_over',
}

// Position interfaces
export interface Position {
	x: number
	y: number
}

export interface TilePosition {
	x: number
	y: number
}

// Actor base interface
export interface ActorState {
	pixel: Position
	tile: TilePosition
	tilePixel: Position
	distToMid: Position
	dir: Position
	dirEnum: Direction
	frames: number
	steps: number
}

// Player specific state
export interface PlayerState extends ActorState {
	nextDir: Position
	nextDirEnum: Direction
	inputDirEnum: Direction | undefined
	stopped: boolean
	eatPauseFramesLeft: number
	lastMeal: Position
}

// Ghost specific state
export interface GhostState extends ActorState {
	mode: GhostMode
	scared: boolean
	sigReverse: boolean
	sigLeaveHome: boolean
	faceDirEnum: Direction
	elroy: number
	targetTile: TilePosition
	targetting: string | undefined
	color: string
	cornerTile: TilePosition
	startPixel: Position
	startDirEnum: Direction
	startMode: GhostMode
	arriveHomeMode: GhostMode
}

// Map tunnel info
export interface TunnelInfo {
	leftEntrance: number
	rightEntrance: number
	leftExit: number
	rightExit: number
}

// Wall path point for rendering
export interface PathPoint {
	x: number
	y: number
	cx?: number
	cy?: number
}

// Energizer state
export interface EnergizerState {
	active: boolean
	count: number
	points: number
	pointsFramesLeft: number
}

// Ghost commander state
export interface GhostCommanderState {
	frame: number
	command: GhostCommand
}

// Ghost releaser state
export interface GhostReleaserState {
	mode: ReleaserMode
	framesSinceLastDot: number
	ghostCounts: Record<number, number>
	globalCount: number
}

// Open tiles for pathfinding
export type OpenTiles = Record<Direction, boolean>

// Game configuration from props
export interface GameConfig {
	lives: number
	brandColor?: string
	gameTitle?: string
	maxPoints?: number
}

// Full game state
export interface GameStateData {
	state: GameState
	level: number
	score: number
	lives: number
	highScore: number
	frame: number
}
