// Energizer system - handles power pellet timing and ghost points

import {
	ENERGIZER_DURATION,
	ENERGIZER_FLASHES,
	FLASH_INTERVAL,
	POINTS_DISPLAY_DURATION,
	FPS,
} from '../constants'
import type { Ghost } from '../core/Ghost'

/**
 * Energizer system manages:
 * - Duration of frightened mode
 * - Ghost flashing near end of energizer
 * - Points display after eating ghosts
 */
export class Energizer {
	private count: number = 0
	private active: boolean = false
	private points: number = 100
	private pointsFramesLeft: number = 0
	private level: number = 1
	private ghosts: Ghost[] = []

	/**
	 * Set references to ghosts
	 */
	setGhosts(ghosts: Ghost[]): void {
		this.ghosts = ghosts
	}

	/**
	 * Set current level
	 */
	setLevel(level: number): void {
		this.level = level
	}

	/**
	 * Get energizer duration in frames for current level
	 */
	getDuration(): number {
		const i = Math.min(this.level, 18) - 1
		return (i >= 0 ? ENERGIZER_DURATION[i] : 0) * FPS
	}

	/**
	 * Get number of ghost flashes for current level
	 */
	getFlashes(): number {
		const i = Math.min(this.level, 18) - 1
		return i >= 0 ? ENERGIZER_FLASHES[i] : 0
	}

	/**
	 * Reset energizer state
	 */
	reset(): void {
		this.count = 0
		this.active = false
		this.points = 100
		this.pointsFramesLeft = 0

		// Reset ghost scared state
		for (const ghost of this.ghosts) {
			ghost.scared = false
		}
	}

	/**
	 * Update energizer each frame
	 */
	update(): void {
		if (this.active) {
			if (this.count >= this.getDuration()) {
				this.reset()
			} else {
				this.count++
			}
		}
	}

	/**
	 * Activate energizer (when pacman eats power pellet)
	 */
	activate(): void {
		this.active = true
		this.count = 0
		this.points = 100 // Reset ghost point multiplier

		// Trigger onEnergized for all ghosts
		for (const ghost of this.ghosts) {
			ghost.onEnergized()
		}

		// If no duration, immediately reset
		if (this.getDuration() === 0) {
			this.reset()
		}
	}

	/**
	 * Check if energizer is currently active
	 */
	isActive(): boolean {
		return this.active
	}

	/**
	 * Check if ghosts should be flashing (near end of energizer)
	 */
	isFlash(): boolean {
		const duration = this.getDuration()
		const flashes = this.getFlashes()
		const i = Math.floor((duration - this.count) / FLASH_INTERVAL)
		return i <= 2 * flashes - 1 ? i % 2 === 0 : false
	}

	/**
	 * Get current ghost point value
	 */
	getPoints(): number {
		return this.points
	}

	/**
	 * Add points for eating a ghost (doubles for next ghost)
	 */
	addPoints(): number {
		const earned = this.points * 2
		this.points *= 2
		this.pointsFramesLeft = POINTS_DISPLAY_DURATION * FPS
		return earned
	}

	/**
	 * Check if points are currently being displayed
	 */
	showingPoints(): boolean {
		return this.pointsFramesLeft > 0
	}

	/**
	 * Update points display timer
	 */
	updatePointsTimer(): void {
		if (this.pointsFramesLeft > 0) {
			this.pointsFramesLeft--
		}
	}
}
