import React, { useState, useCallback, useRef, Suspense } from 'react'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { isMobile } from '../../../../utils/functions'
import type { RhythmHighwayProps } from './types'
import { DEFAULT_LANE_COLORS, LANE_LABELS } from './constants'
import type { GameUIState } from './game'

const GAME_FONT_FAMILY = '"Orbitron", sans-serif'

const RhythmHighway3DCore = React.lazy(() => import('./game'))

const RhythmHighway3D: React.FC<RhythmHighwayProps> = ({
	setGameOver,
	setPointsEarned,
	brandColor = '#8b5cf6',
	initialLives = 3,
	gameTitle = 'RHYTHM HIGHWAY 3D',
	brandLogo,
	maxPoints,
}) => {
	const mobile = isMobile()

	// Game flow
	const [gameStarted, setGameStarted] = useState(false)
	const [gamePaused, setGamePaused] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [wasGamePaused, setWasGamePaused] = useState(false)
	const [instructionsStep, setInstructionsStep] = useState(0)
	const [audioMuted, setAudioMuted] = useState(false)

	// Display state polled from engine
	const [points, setPoints] = useState(0)
	const [currentLives, setCurrentLives] = useState(initialLives)

	// UI state from engine
	const uiRef = useRef<GameUIState | null>(null)
	const [uiState, setUiState] = useState<GameUIState | null>(null)

	const handleUIStateChange = useCallback((state: GameUIState) => {
		uiRef.current = state
		setUiState({ ...state })
	}, [])

	const handlePointsChange = useCallback((pts: number) => {
		setPoints(pts)
	}, [])

	const handleLivesChange = useCallback((lives: number) => {
		setCurrentLives(lives)
	}, [])

	const handleGameOver = useCallback(
		(finalPoints: number) => {
			setGameStarted(false)
			setPointsEarned(finalPoints)
			setGameOver(true)
		},
		[setGameOver, setPointsEarned]
	)

	const startGame = () => {
		setInstructionsStep(0)
		setPoints(0)
		setCurrentLives(initialLives)
		setGamePaused(false)
		setQuitGame(false)
		setGameStarted(true)
	}

	const cancelQuit = () => {
		setQuitGame(false)
		setGamePaused(wasGamePaused)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(maxPoints ? Math.min(points, maxPoints) : points)
		setGameOver(true)
		setGameStarted(false)
	}

	const toggleMute = () => {
		const newMuted = !audioMuted
		setAudioMuted(newMuted)
		// audioManager.setMuted is called internally
	}

	const level = uiState?.level ?? 1
	const isCountingDown = uiState?.isCountingDown ?? false

	return (
		<div
			className="game-column-fill"
			style={{ backgroundColor: brandColor }}
		>
			{/* Game Header */}
			<GameHeader
				level={level}
				lives={currentLives}
				onPause={
					gameStarted && !quitGame && !uiState?.showLevelUp && !isCountingDown
						? () => setGamePaused(!gamePaused)
						: undefined
				}
				isPaused={gamePaused}
				brandColor={brandColor}
				isMobile={mobile}
				onQuit={() => {
					setQuitGame(true)
					setWasGamePaused(gamePaused)
					setGamePaused(true)
				}}
				showQuitButton={gameStarted && !isCountingDown}
				isQuitting={quitGame}
			/>

			{/* Game Container */}
			<div className="game-center-area-tight">
				<div
					className="game-container game-column-narrow"
					style={{ position: 'relative', backgroundColor: brandColor }}
				>
					{/* Active 3D Game */}
					{gameStarted && (
						<>
							<Suspense fallback={
								<div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '1.5rem' }}>
									<style>{`
										@keyframes eqBar {
											0%, 100% { transform: scaleY(0.15); }
											50%       { transform: scaleY(1); }
										}
									`}</style>
									<div style={{ display: 'flex', alignItems: 'flex-end', gap: '0.5rem', height: '60px' }}>
										{[
											{ color: '#00ffff', delay: '0s' },
											{ color: '#ff00ff', delay: '0.18s' },
											{ color: '#ffff00', delay: '0.36s' },
											{ color: '#00ff00', delay: '0.54s' },
										].map(({ color, delay }, i) => (
											<div
												key={i}
												style={{
													width: '14px',
													height: '60px',
													backgroundColor: color,
													borderRadius: '3px',
													transformOrigin: 'bottom',
													boxShadow: `0 0 8px ${color}, 0 0 20px ${color}66`,
													animation: 'eqBar 0.72s ease-in-out infinite',
													animationDelay: delay,
												}}
											/>
										))}
									</div>
									<p
										style={{
											color: '#ffffff',
											fontSize: '13px',
											fontFamily: 'ui-monospace, monospace',
											letterSpacing: '0.15em',
											textTransform: 'uppercase',
											opacity: 0.85,
										}}
									>
										Cargando...
									</p>
								</div>
							}>
							<RhythmHighway3DCore
								brandColor={brandColor}
								initialLives={initialLives}
								onGameOver={handleGameOver}
								onPointsChange={handlePointsChange}
								onLivesChange={handleLivesChange}
								onUIStateChange={handleUIStateChange}
								onTogglePause={() => setGamePaused(!gamePaused)}
								gamePaused={gamePaused || quitGame}
								quitRequested={quitGame}
								maxPoints={maxPoints}
							/>
							</Suspense>

							{/* HUD Overlay (pointer-events-none) */}
							<div
								className="game-overlay-passthrough"
								style={{ fontFamily: GAME_FONT_FAMILY }}
							>
								{/* Countdown keyframe animations */}
								<style>{`
									@keyframes countdownPulse {
										0% { transform: scale(1.2); opacity: 1; }
										100% { transform: scale(0.8); opacity: 0.6; }
									}
									@keyframes vamosZoom {
										0% { transform: scale(0.6); opacity: 1; }
										100% { transform: scale(1); opacity: 0.7; }
									}
								`}</style>

								{/* Countdown */}
								{uiState?.isCountingDown && uiState.countdownValue && (
									<div className="game-rhythm-countdown-area">
										<div
											key={uiState.countdownValue}
											style={{
												fontWeight: 'bold',
												fontSize: 'clamp(3rem, 12vw, 6rem)',
												textShadow: `0 0 40px ${brandColor}, 0 0 80px ${brandColor}`,
												color:
													uiState.countdownValue === '¡VAMOS!'
														? brandColor
														: '#ffffff',
												animation:
													uiState.countdownValue === '¡VAMOS!'
														? 'vamosZoom 0.5s ease-out forwards'
														: 'countdownPulse 1s ease-out forwards',
											}}
										>
											{uiState.countdownValue}
										</div>
										{uiState.songTitle && (
											<div className="game-rhythm-countdown-song">
												<p style={{ color: 'white', fontSize: '0.875rem', fontWeight: 'bold', opacity: 0.8 }}>
													{uiState.songTitle}
												</p>
												<p style={{ color: 'white', fontSize: '0.75rem', opacity: 0.6, marginTop: '0.25rem' }}>
													{uiState.difficultyName}
												</p>
											</div>
										)}
									</div>
								)}

								{/* Top-left: Combo + Hit stats */}
								<div className="game-rhythm-combo-pos">
									<div className="game-rhythm-panel game-rhythm-combo-panel">
										<p className="game-rhythm-panel-label">
											COMBO
										</p>
										<p
											className="game-rhythm-panel-value"
											style={{
												color: (uiState?.combo ?? 0) > 0 ? '#facc15' : 'rgba(255, 255, 255, 0.35)',
												textAlign: 'center',
											}}
										>
											x{uiState?.combo ?? 0}
										</p>
										<div className="game-rhythm-panel-divider" />
										<div className="game-rhythm-hits-list">
											<div className="game-rhythm-hit-row">
												<span style={{ color: '#ffd700' }}>★</span>
												<span style={{ color: '#ffd700' }}>
													{uiState?.perfectCount ?? 0}
												</span>
											</div>
											<div className="game-rhythm-hit-row">
												<span style={{ color: '#c0c0c0' }}>✓</span>
												<span style={{ color: '#c0c0c0' }}>
													{uiState?.goodCount ?? 0}
												</span>
											</div>
											<div className="game-rhythm-hit-row">
												<span style={{ color: '#ff8c00' }}>◆</span>
												<span style={{ color: '#ff8c00' }}>
													{uiState?.badCount ?? 0}
												</span>
											</div>
											<div className="game-rhythm-hit-row">
												<span style={{ color: '#ff4444' }}>✗</span>
												<span style={{ color: '#ff4444' }}>
													{uiState?.missCount ?? 0}
												</span>
											</div>
										</div>
									</div>
								</div>

								{/* Top-right: Score */}
								<div className="game-rhythm-score-pos">
									<div className="game-rhythm-panel">
										<p className="game-rhythm-panel-label">
											PUNTOS
										</p>
										<p className="game-rhythm-panel-value" style={{ color: 'white', textAlign: 'center' }}>
											{points.toLocaleString()}
										</p>
									</div>
								</div>

								{/* Lane key labels (desktop only) */}
								{!mobile && uiState && !uiState.isCountingDown && (
									<div className="game-rhythm-lane-labels">
										{LANE_LABELS.map((label, i) => {
											const colors = [
												DEFAULT_LANE_COLORS.lane0,
												DEFAULT_LANE_COLORS.lane1,
												DEFAULT_LANE_COLORS.lane2,
												DEFAULT_LANE_COLORS.lane3,
											]
											const xPct = uiState.laneScreenPositions?.[i]
											if (xPct == null) return null
											return (
												<span
													key={label}
													className="game-rhythm-lane-label"
													style={{
														left: `${xPct}%`,
														transform: 'translateX(-50%)',
														color: colors[i],
														opacity: 0.7,
														textShadow: `0 0 10px ${colors[i]}`,
														fontFamily: GAME_FONT_FAMILY,
													}}
												>
													{label}
												</span>
											)
										})}
									</div>
								)}

								{/* Hit effect text with radial glow */}
								{uiState?.hitEffects.map(effect => {
									const elapsed = Date.now() - effect.time
									const progress = elapsed / 500
									if (progress > 1) return null

									// Position based on projected lane screen position
									const lanePercent =
										uiState.laneScreenPositions?.[effect.lane] ??
										(effect.lane + 0.5) * (100 / 4)

									const label =
										effect.type === 'perfect'
											? '¡PERFECTO!'
											: effect.type === 'good'
												? 'BIEN'
												: effect.type === 'bad'
													? 'OK'
													: 'FALLO'
									const color =
										effect.type === 'perfect'
											? '#ffd700'
											: effect.type === 'good'
												? '#c0c0c0'
												: effect.type === 'bad'
													? '#ff8c00'
													: '#ff4444'

									// Radial glow size per type
									const glowSize =
										effect.type === 'perfect'
											? 30 + progress * 20
											: effect.type === 'good'
												? 20 + progress * 15
												: effect.type === 'bad'
													? 15 + progress * 10
													: 0

									return (
										<div
											key={effect.id}
											className="game-rhythm-hit-effect"
											style={{
												left: `${lanePercent}%`,
												bottom: `${24 + progress * 12}%`,
												transform: 'translateX(-50%)',
												color,
												opacity: 1 - progress,
												textShadow: `0 0 10px ${color}, 0 0 20px ${color}`,
												fontFamily: GAME_FONT_FAMILY,
												fontSize:
													effect.type === 'perfect'
														? '16px'
														: effect.type === 'good'
															? '14px'
															: '13px',
											}}
										>
											{glowSize > 0 && (
												<div
													className="game-rhythm-hit-glow"
													style={{
														width: glowSize * 2,
														height: glowSize * 2,
														transform: 'translate(-50%, -50%)',
														background: `radial-gradient(circle, ${color}55 0%, ${color}22 50%, transparent 70%)`,
													}}
												/>
											)}
											{label}
										</div>
									)
								})}
							</div>
						</>
					)}

					{/* Start Screen */}
					{!gameStarted && (
						<GameOverlay
							type="custom"
							title={`🎵 ${gameTitle}`}
							brandColor={brandColor}
							onAction={
								instructionsStep === 0
									? () => setInstructionsStep(1)
									: startGame
							}
							actionText={instructionsStep === 0 ? 'Siguiente →' : '🎮 JUGAR'}
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									{instructionsStep === 0 ? (
										<>
											<div className="game-rhythm-keys-demo">
												{Object.entries(DEFAULT_LANE_COLORS).map(
													([key, color], i) => (
														<div
															key={key}
															className="game-rhythm-key-demo"
														>
															<div
																className="game-rhythm-key-box"
																style={{ backgroundColor: color }}
															/>
															<span>{LANE_LABELS[i]}</span>
														</div>
													)
												)}
											</div>
											<div className="game-rhythm-instruction-text">
												{mobile ? (
													<>
														<p>👆 Toca los carriles cuando las notas</p>
														<p>lleguen a la zona de impacto</p>
													</>
												) : (
													<>
														<p>⌨️ Usa D, F, J, K para los 4 carriles</p>
														<p>⏸ ESPACIO o P para pausar</p>
													</>
												)}
											</div>
											<button
												onClick={startGame}
												className="game-skip-link"
											>
												Omitir
											</button>
										</>
									) : (
										<>
											<div className="game-rhythm-instruction-list">
												<div className="game-rhythm-instruction-detail">
													<p>
														🎯 Golpea las notas en el momento exacto
														<br />
														¡Cada canción tiene su melodía!
														<br />
														Conforme avanzas se volverá más difícil
													</p>
												</div>
												<p>✨ PERFECTO = 50 pts × combo</p>
												<p>👍 BIEN = 25 pts × combo</p>
												<p>👌 OK = 10 pts (sin combo)</p>
												<p>🎵 MANTENER = notas largas dan bonus extra</p>
												<p>❌ FALLO = pierdes una vida</p>
												<p>🔥 ¡Mantén el combo para más puntos!</p>
											</div>
											<button
												onClick={() => setInstructionsStep(0)}
												className="game-skip-link"
											>
												← Atrás
											</button>
										</>
									)}
								</div>
							}
						/>
					)}

					{/* Level Up Overlay */}
					{uiState?.showLevelUp && (
						<GameOverlay
							type="custom"
							title="🎉 ¡NIVEL COMPLETADO!"
							message={`¡Pasaste al Nivel ${level + 1}!`}
							brandColor={brandColor}
							customContent={
								<div className="game-start-content">
									<p style={{ fontSize: '1.125rem', color: '#facc15', fontWeight: 'bold', marginBottom: '0.5rem' }}>
										🎵 {uiState.nextSongTitle}
									</p>
									<p style={{ fontSize: '0.875rem', color: '#d1d5db', marginBottom: '0.25rem' }}>
										por {uiState.nextSongArtist}
									</p>
									<p style={{ fontSize: '0.875rem', color: '#9ca3af' }}>
										{uiState.nextCycle > 0
											? `¡Velocidad x${uiState.nextCycle + 1}!`
											: `Nueva melodía: ${uiState.nextDifficultyName}`}
									</p>
								</div>
							}
						/>
					)}

					{/* Pause Overlay */}
					{gamePaused && !quitGame && !uiState?.showLevelUp && (
						<GameOverlay
							type="pause"
							message={`Nivel ${level}: ${uiState?.displayName || ''}`}
							brandColor={brandColor}
							onAction={() => setGamePaused(false)}
							actionText="▶️ CONTINUAR"
							customContent={
								<button
									onClick={toggleMute}
									className="game-rhythm-mute-btn"
								>
									{audioMuted ? '🔇 Sonido desactivado' : '🔊 Sonido activado'}
								</button>
							}
						/>
					)}

					{/* Quit Confirmation Overlay */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`Nivel ${level} • ${points} puntos`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										🔄 Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										❌ Salir
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>

			{/* Stats bar */}
			<div className="game-rhythm-stats-bar">
				{gameStarted && uiState && (
					<>
						<span>🎵 {uiState.displayName}</span>
						<span>|</span>
						<span>Combo máximo: {uiState.maxCombo}</span>
					</>
				)}
			</div>
		</div>
	)
}

export default RhythmHighway3D
