// Game loop hook for Pac-Man

import { useRef, useCallback, useEffect } from 'react'
import { Direction, GhostMode, GameState } from '../types'
import {
	FPS,
	PELLET_POINTS,
	ENERGIZER_POINTS,
	EXTRA_LIFE_SCORE,
	PACMAN_START,
	BLINKY_START,
	PINKY_START,
	INKY_START,
	CLYDE_START,
} from '../constants'
import { GameMap } from '../core/Map'
import { Player } from '../core/Player'
import { Fruit } from '../core/Fruit'
import { Blinky, Pinky, Inky, Clyde, createGhosts } from '../core/Targets'
import { Energizer } from '../systems/Energizer'
import { GhostCommander } from '../systems/GhostCommander'
import { GhostReleaser } from '../systems/GhostReleaser'
import { Renderer } from '../utils/renderer'
import { pacmanAudio } from '../utils/audioManager'
import { hapticManager } from '../../utils/hapticManager'

interface GameLoopState {
	gameState: GameState
	score: number
	lives: number
	level: number
	frame: number
}

interface UseGameLoopOptions {
	canvasRef: React.RefObject<HTMLCanvasElement>
	initialLives: number
	maxPoints?: number
	onScoreChange?: (score: number) => void
	onLivesUpdate?: (lives: number) => void
	onGameOver?: (score: number) => void
	onLevelComplete?: () => void
}

export function useGameLoop({
	canvasRef,
	initialLives,
	maxPoints,
	onScoreChange,
	onLivesUpdate,
	onGameOver,
	onLevelComplete,
}: UseGameLoopOptions) {
	// Game objects
	const mapRef = useRef<GameMap | null>(null)
	const playerRef = useRef<Player | null>(null)
	const ghostsRef = useRef<{
		blinky: Blinky
		pinky: Pinky
		inky: Inky
		clyde: Clyde
	} | null>(null)
	const energizerRef = useRef<Energizer | null>(null)
	const commanderRef = useRef<GhostCommander | null>(null)
	const releaserRef = useRef<GhostReleaser | null>(null)
	const fruitRef = useRef<Fruit | null>(null)
	const rendererRef = useRef<Renderer | null>(null)

	// Game state
	const stateRef = useRef<GameLoopState>({
		gameState: GameState.READY,
		score: 0,
		lives: initialLives,
		level: 1,
		frame: 0,
	})

	// Animation frame ID
	const animationFrameRef = useRef<number | null>(null)
	const lastTimeRef = useRef<number>(0)
	const accumulatorRef = useRef<number>(0)

	// Death animation state
	const deathFrameRef = useRef<number>(0)
	const readyFrameRef = useRef<number>(0)

	// Extra life tracking
	const lastExtraLifeScoreRef = useRef<number>(0)

	/**
	 * Initialize game objects
	 */
	const initGame = useCallback(() => {
		if (!canvasRef.current) return

		const ctx = canvasRef.current.getContext('2d')
		if (!ctx) return

		// Create map
		const map = new GameMap()
		mapRef.current = map

		// Create player
		const player = new Player()
		player.setMap(map)
		player.startPixel = { ...PACMAN_START.pixel }
		player.startDirEnum = PACMAN_START.dirEnum as Direction
		playerRef.current = player

		// Create ghosts
		const ghosts = createGhosts()
		ghostsRef.current = ghosts

		// Configure Blinky
		ghosts.blinky.setMap(map)
		ghosts.blinky.startPixel = { ...BLINKY_START.pixel }
		ghosts.blinky.startDirEnum = BLINKY_START.dirEnum as Direction
		ghosts.blinky.cornerTile = { ...BLINKY_START.cornerTile }
		ghosts.blinky.startMode = BLINKY_START.startMode as GhostMode
		ghosts.blinky.arriveHomeMode = BLINKY_START.arriveHomeMode as GhostMode
		ghosts.blinky.setPlayerRef(player)

		// Configure Pinky
		ghosts.pinky.setMap(map)
		ghosts.pinky.startPixel = { ...PINKY_START.pixel }
		ghosts.pinky.startDirEnum = PINKY_START.dirEnum as Direction
		ghosts.pinky.cornerTile = { ...PINKY_START.cornerTile }
		ghosts.pinky.startMode = PINKY_START.startMode as GhostMode
		ghosts.pinky.arriveHomeMode = PINKY_START.arriveHomeMode as GhostMode
		ghosts.pinky.setPlayerRef(player)

		// Configure Inky
		ghosts.inky.setMap(map)
		ghosts.inky.startPixel = { ...INKY_START.pixel }
		ghosts.inky.startDirEnum = INKY_START.dirEnum as Direction
		ghosts.inky.cornerTile = { ...INKY_START.cornerTile }
		ghosts.inky.startMode = INKY_START.startMode as GhostMode
		ghosts.inky.arriveHomeMode = INKY_START.arriveHomeMode as GhostMode
		ghosts.inky.setPlayerRef(player)

		// Configure Clyde
		ghosts.clyde.setMap(map)
		ghosts.clyde.startPixel = { ...CLYDE_START.pixel }
		ghosts.clyde.startDirEnum = CLYDE_START.dirEnum as Direction
		ghosts.clyde.cornerTile = { ...CLYDE_START.cornerTile }
		ghosts.clyde.startMode = CLYDE_START.startMode as GhostMode
		ghosts.clyde.arriveHomeMode = CLYDE_START.arriveHomeMode as GhostMode
		ghosts.clyde.setPlayerRef(player)

		const ghostArray = [ghosts.blinky, ghosts.pinky, ghosts.inky, ghosts.clyde]

		// Create energizer
		const energizer = new Energizer()
		energizer.setGhosts(ghostArray)
		energizerRef.current = energizer

		// Create commander
		const commander = new GhostCommander()
		commander.setGhosts(ghostArray)
		commander.setEnergizer(energizer)
		commanderRef.current = commander

		// Set ghost references to commander
		for (const ghost of ghostArray) {
			ghost.setReferences(
				map,
				player,
				() => commander.getCommand(),
				stateRef.current.level
			)
		}

		// Create releaser
		const releaser = new GhostReleaser()
		releaser.setGhosts(ghostArray)
		releaserRef.current = releaser

		// Create fruit
		const fruit = new Fruit()
		fruitRef.current = fruit

		// Create renderer
		const renderer = new Renderer(ctx)
		renderer.initMapCanvas(map)
		rendererRef.current = renderer

		// Reset everything
		resetLevel(true)
	// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [canvasRef])

	/**
	 * Reset for new level or restart
	 */
	const resetLevel = useCallback((newLevel: boolean) => {
		const state = stateRef.current

		if (newLevel) {
			mapRef.current?.resetCurrent()
			releaserRef.current?.onNewLevel()
			fruitRef.current?.onNewLevel(state.level)
		} else {
			releaserRef.current?.onRestartLevel()
		}

		fruitRef.current?.reset()

		playerRef.current?.reset()
		playerRef.current?.setLevel(state.level)

		const ghosts = ghostsRef.current
		if (ghosts) {
			const ghostArray = [
				ghosts.blinky,
				ghosts.pinky,
				ghosts.inky,
				ghosts.clyde,
			]
			for (const ghost of ghostArray) {
				ghost.reset()
				ghost.setLevel(state.level)
			}
		}

		energizerRef.current?.reset()
		energizerRef.current?.setLevel(state.level)
		commanderRef.current?.reset()
		commanderRef.current?.setLevel(state.level)

		state.frame = 0
		readyFrameRef.current = 0
		deathFrameRef.current = 0
	}, [])

	/**
	 * Add score
	 */
	const addScore = useCallback(
		(points: number) => {
			const state = stateRef.current
			const prevScore = state.score
			state.score += points
			onScoreChange?.(state.score)

			// Haptic feedback for score milestones (every 1000 points)
			if (Math.floor(state.score / 1000) > Math.floor(prevScore / 1000)) {
				hapticManager.comboMilestone()
			}

			// Check for extra life
			if (state.score >= lastExtraLifeScoreRef.current + EXTRA_LIFE_SCORE) {
				state.lives++
				lastExtraLifeScoreRef.current += EXTRA_LIFE_SCORE
				onLivesUpdate?.(state.lives)
				pacmanAudio.playExtraLife()
				hapticManager.perfectHit()
			}

			// Check for max points win condition
			if (maxPoints && state.score >= maxPoints) {
				state.gameState = GameState.GAME_OVER
				onGameOver?.(state.score)
			}
		},
		[onScoreChange, onLivesUpdate, onGameOver, maxPoints]
	)

	/**
	 * Handle player death
	 */
	const handleDeath = useCallback(() => {
		const state = stateRef.current
		state.lives--
		onLivesUpdate?.(state.lives)
		state.gameState = GameState.DYING
		deathFrameRef.current = 0
		pacmanAudio.playDeath()
		hapticManager.miss()
	}, [onLivesUpdate])

	/**
	 * Check collision between player and ghosts
	 */
	const checkCollisions = useCallback(() => {
		const player = playerRef.current
		const ghosts = ghostsRef.current
		const energizer = energizerRef.current
		if (!player || !ghosts || !energizer) return

		const ghostArray = [ghosts.blinky, ghosts.pinky, ghosts.inky, ghosts.clyde]

		for (const ghost of ghostArray) {
			// Skip ghosts that are eaten or going home or in home
			if (
				ghost.mode === GhostMode.EATEN ||
				ghost.mode === GhostMode.GOING_HOME ||
				ghost.mode === GhostMode.ENTERING_HOME ||
				ghost.mode === GhostMode.PACING_HOME ||
				ghost.mode === GhostMode.LEAVING_HOME
			) {
				continue
			}

			// Check if on same tile
			if (player.tile.x === ghost.tile.x && player.tile.y === ghost.tile.y) {
				if (ghost.scared) {
					// Eat ghost
					ghost.onEaten()
					const points = energizer.addPoints()
					addScore(points)
					pacmanAudio.playGhostEaten()
				} else {
					// Player dies
					handleDeath()
					return
				}
			}
		}
	}, [addScore, handleDeath])

	/**
	 * Update game state for one frame
	 */
	const updateFrame = useCallback(() => {
		const state = stateRef.current
		const map = mapRef.current
		const player = playerRef.current
		const ghosts = ghostsRef.current
		const energizer = energizerRef.current
		const commander = commanderRef.current
		const releaser = releaserRef.current
		const fruit = fruitRef.current

		if (!map || !player || !ghosts || !energizer || !commander || !releaser)
			return

		// Update systems
		commander.update()
		releaser.update()
		energizer.update()
		fruit?.update()

		// Update player energizer state
		player.setEnergizerActive(energizer.isActive())

		const ghostArray = [ghosts.blinky, ghosts.pinky, ghosts.inky, ghosts.clyde]

		// 2 substeps per frame for smoother collision detection
		for (let j = 0; j < 2; j++) {
			// Update player
			player.update(j)

			// Check eating
			const eaten = player.checkEating()
			if (eaten === '.') {
				addScore(PELLET_POINTS)
				releaser.onDotEat()
				fruit?.onDotEat(map.dotsEaten)
				pacmanAudio.startEating()
			} else if (eaten === 'o') {
				addScore(ENERGIZER_POINTS)
				energizer.activate()
				releaser.onDotEat()
				fruit?.onDotEat(map.dotsEaten)
				pacmanAudio.playPowerPellet()
				pacmanAudio.startEating()
			}

			// Check fruit collision
			if (fruit) {
				const fruitPoints = fruit.testCollide(player.pixel)
				if (fruitPoints > 0) {
					addScore(fruitPoints)
					pacmanAudio.startEating()
					hapticManager.comboMilestone()
				}
			}

			// Check level complete
			if (map.allDotsEaten()) {
				state.gameState = GameState.LEVEL_COMPLETE
				return
			}

			// Check collisions before ghost movement
			checkCollisions()
			if (state.gameState === GameState.DYING) return

			// Update ghosts
			for (const ghost of ghostArray) {
				ghost.update(j)
			}

			// Check collisions after ghost movement
			checkCollisions()
			if ((state.gameState as GameState) === GameState.DYING) return
		}

		// Increment frame counter
		state.frame++

		// Increment ghost frames for animation
		for (const ghost of ghostArray) {
			ghost.frames++
		}

		// Update energizer points timer
		energizer.updatePointsTimer()
	}, [addScore, checkCollisions])

	/**
	 * Render current frame
	 */
	const render = useCallback(() => {
		const state = stateRef.current
		const map = mapRef.current
		const player = playerRef.current
		const ghosts = ghostsRef.current
		const energizer = energizerRef.current
		const renderer = rendererRef.current
		const fruit = fruitRef.current

		if (!map || !player || !ghosts || !energizer || !renderer) return

		const ghostArray = [ghosts.blinky, ghosts.pinky, ghosts.inky, ghosts.clyde]

		switch (state.gameState) {
			case GameState.READY:
				renderer.render(map, player, ghostArray, energizer, state.frame, fruit)
				renderer.drawHUD(state.score, state.lives, state.level)
				renderer.drawReady()
				break

			case GameState.PLAYING:
				renderer.render(map, player, ghostArray, energizer, state.frame, fruit)
				renderer.drawHUD(state.score, state.lives, state.level)
				break

			case GameState.DYING:
				renderer.clear()
				// Draw walls only
				if (renderer['mapCanvas']) {
					const ctx = canvasRef.current?.getContext('2d')
					if (ctx) {
						ctx.drawImage(renderer['mapCanvas'], 0, 0)
					}
				}
				renderer.drawDeathAnimation(player, deathFrameRef.current)
				renderer.drawHUD(state.score, state.lives, state.level)
				break

			case GameState.GAME_OVER:
				renderer.render(map, player, ghostArray, energizer, state.frame, fruit)
				renderer.drawHUD(state.score, state.lives, state.level)
				renderer.drawGameOver()
				break

			case GameState.PAUSED:
				renderer.render(map, player, ghostArray, energizer, state.frame, fruit)
				renderer.drawHUD(state.score, state.lives, state.level)
				break
		}
	}, [canvasRef])

	/**
	 * Main game loop
	 */
	const gameLoop = useCallback(
		(timestamp: number) => {
			const state = stateRef.current

			// Calculate delta time
			if (lastTimeRef.current === 0) {
				lastTimeRef.current = timestamp
			}
			const deltaTime = timestamp - lastTimeRef.current
			lastTimeRef.current = timestamp

			// Accumulate time
			accumulatorRef.current += deltaTime
			const frameTime = 1000 / FPS

			// Update eating sound timeout
			pacmanAudio.updateEating()

			// Handle different game states
			switch (state.gameState) {
				case GameState.READY:
					// Play start jingle on first frame of ready
					if (readyFrameRef.current === 0) {
						pacmanAudio.playStartJingle()
					}
					readyFrameRef.current++
					if (readyFrameRef.current >= FPS * 2) {
						// 2 second ready screen
						state.gameState = GameState.PLAYING
						accumulatorRef.current = 0 // Reset to prevent speed burst
					}
					render()
					break

				case GameState.PLAYING:
					// Update at fixed timestep
					while (accumulatorRef.current >= frameTime) {
						updateFrame()
						accumulatorRef.current -= frameTime

						// Check if state changed during update
						if (state.gameState !== GameState.PLAYING) break
					}
					render()
					break

				case GameState.DYING:
					deathFrameRef.current++
					if (deathFrameRef.current >= FPS) {
						// 1 second death animation
						if (state.lives > 0) {
							resetLevel(false)
							state.gameState = GameState.READY
							readyFrameRef.current = 0
							pacmanAudio.resetStartJingle()
						} else {
							state.gameState = GameState.GAME_OVER
							onGameOver?.(state.score)
						}
					}
					render()
					break

				case GameState.LEVEL_COMPLETE:
					// Brief pause then next level
					pacmanAudio.stopEating()
					pacmanAudio.resetStartJingle()
					state.level++
					resetLevel(true)
					state.gameState = GameState.READY
					readyFrameRef.current = 0
					onLevelComplete?.()
					hapticManager.levelUp()
					break

				case GameState.PAUSED:
					pacmanAudio.stopEating()
					render()
					break

				case GameState.GAME_OVER:
					pacmanAudio.stopEating()
					render()
					break
			}

			// Continue loop
			if (state.gameState !== GameState.GAME_OVER) {
				animationFrameRef.current = requestAnimationFrame(gameLoop)
			}
		},
		[updateFrame, render, resetLevel, onGameOver, onLevelComplete]
	)

	/**
	 * Start the game
	 */
	const startGame = useCallback(() => {
		initGame()
		lastTimeRef.current = 0
		accumulatorRef.current = 0
		animationFrameRef.current = requestAnimationFrame(gameLoop)
	}, [initGame, gameLoop])

	/**
	 * Pause/unpause the game
	 */
	const togglePause = useCallback(() => {
		const state = stateRef.current
		if (state.gameState === GameState.PLAYING) {
			state.gameState = GameState.PAUSED
		} else if (state.gameState === GameState.PAUSED) {
			state.gameState = GameState.PLAYING
			lastTimeRef.current = 0
			animationFrameRef.current = requestAnimationFrame(gameLoop)
		}
	}, [gameLoop])

	/**
	 * Handle direction input
	 */
	const setDirection = useCallback((direction: Direction) => {
		playerRef.current?.setInputDir(direction)
	}, [])

	/**
	 * Get current game state
	 */
	const getState = useCallback(() => stateRef.current, [])

	// Cleanup on unmount
	useEffect(() => {
		return () => {
			if (animationFrameRef.current) {
				cancelAnimationFrame(animationFrameRef.current)
			}
			pacmanAudio.stopEating()
		}
	}, [])

	return {
		startGame,
		togglePause,
		setDirection,
		getState,
	}
}
