import * as Tone from 'tone'

export class RacingAudioManager {
	private initialized = false
	private muted = false

	// Engine oscillator (continuous)
	private engineOsc: Tone.Oscillator | null = null
	private engineGain: Tone.Gain | null = null
	private engineFilter: Tone.Filter | null = null
	private currentSpeed = 0

	// Synthesizers
	private collisionSynth: Tone.MembraneSynth | null = null
	private noiseSynth: Tone.NoiseSynth | null = null
	private coinSynth: Tone.PolySynth | null = null
	private lapSynth: Tone.PolySynth | null = null

	async init(): Promise<void> {
		if (this.initialized) return

		await Tone.start()

		// Engine oscillator - continuous loop with variable pitch
		// Using triangle wave for smoother, less harsh sound
		this.engineGain = new Tone.Gain(0).toDestination()
		this.engineFilter = new Tone.Filter({
			frequency: 400,
			type: 'lowpass',
			rolloff: -24,
		}).connect(this.engineGain)

		this.engineOsc = new Tone.Oscillator({
			frequency: 50,
			type: 'triangle',
			volume: -16,
		}).connect(this.engineFilter)

		// Collision synth - crash thud
		this.collisionSynth = new Tone.MembraneSynth({
			pitchDecay: 0.03,
			octaves: 4,
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.001,
				decay: 0.25,
				sustain: 0,
				release: 0.15,
			},
			volume: -4,
		}).toDestination()

		// Noise synth for crash texture
		this.noiseSynth = new Tone.NoiseSynth({
			noise: { type: 'white' },
			envelope: {
				attack: 0.002,
				decay: 0.15,
				sustain: 0,
				release: 0.1,
			},
			volume: -14,
		}).toDestination()

		// Coin synth - high chime
		this.coinSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'sine' },
			envelope: {
				attack: 0.01,
				decay: 0.15,
				sustain: 0.05,
				release: 0.3,
			},
			volume: -8,
		}).toDestination()

		// Lap complete synth - fanfare
		this.lapSynth = new Tone.PolySynth(Tone.Synth, {
			oscillator: { type: 'triangle' },
			envelope: {
				attack: 0.01,
				decay: 0.2,
				sustain: 0.2,
				release: 0.4,
			},
			volume: -6,
		}).toDestination()

		this.initialized = true
	}

	// Start engine sound
	startEngine(): void {
		if (!this.initialized || this.muted || !this.engineOsc || !this.engineGain)
			return
		this.engineOsc.start()
		this.engineGain.gain.rampTo(0.35, 0.1) // Lower gain for less intrusive sound
	}

	// Stop engine sound
	stopEngine(): void {
		if (!this.engineOsc || !this.engineGain) return
		this.engineGain.gain.rampTo(0, 0.1)
		// Delay stopping to avoid click
		setTimeout(() => {
			try {
				this.engineOsc?.stop()
			} catch {
				// Oscillator may already be stopped
			}
		}, 150)
	}

	// Update engine sound based on speed (0-1 normalized)
	updateEngineSound(speed: number): void {
		if (
			!this.initialized ||
			this.muted ||
			!this.engineOsc ||
			!this.engineFilter
		)
			return

		// Smooth speed changes
		this.currentSpeed = this.currentSpeed * 0.9 + speed * 0.1

		// Map speed to pitch (50Hz idle to 120Hz at max speed) - lower max for smoother sound
		const baseFreq = 50
		const maxFreq = 120
		const targetFreq = baseFreq + this.currentSpeed * (maxFreq - baseFreq)
		this.engineOsc.frequency.rampTo(targetFreq, 0.05)

		// Also adjust filter cutoff (lower range for less harsh highs)
		const baseCutoff = 300
		const maxCutoff = 800
		const targetCutoff =
			baseCutoff + this.currentSpeed * (maxCutoff - baseCutoff)
		this.engineFilter.frequency.rampTo(targetCutoff, 0.05)
	}

	// Crash/collision - thud + noise
	playCollision(): void {
		if (!this.initialized || this.muted) return
		const now = Tone.now()

		if (this.collisionSynth) {
			this.collisionSynth.triggerAttackRelease('C2', '8n', now)
		}
		if (this.noiseSynth) {
			this.noiseSynth.triggerAttackRelease('8n', now)
		}
	}

	// Coin collection - high chime
	playCoinCollect(): void {
		if (!this.initialized || this.muted || !this.coinSynth) return
		const now = Tone.now()
		this.coinSynth.triggerAttackRelease(['E6', 'G6'], '16n', now)
	}

	// Lap complete - fanfare
	playLapComplete(): void {
		if (!this.initialized || this.muted || !this.lapSynth) return
		const now = Tone.now()

		// Quick triumphant arpeggio
		const notes = ['C5', 'E5', 'G5', 'C6']
		notes.forEach((note, i) => {
			this.lapSynth!.triggerAttackRelease(note, '8n', now + i * 0.08)
		})
	}

	setMuted(muted: boolean): void {
		this.muted = muted
		if (muted && this.engineGain) {
			this.engineGain.gain.rampTo(0, 0.1)
		} else if (!muted && this.engineGain && this.currentSpeed > 0) {
			this.engineGain.gain.rampTo(0.35, 0.1)
		}
	}

	isMuted(): boolean {
		return this.muted
	}

	dispose(): void {
		if (!this.initialized) return

		this.stopEngine()

		this.engineOsc?.dispose()
		this.engineGain?.dispose()
		this.engineFilter?.dispose()
		this.collisionSynth?.dispose()
		this.noiseSynth?.dispose()
		this.coinSynth?.dispose()
		this.lapSynth?.dispose()

		this.engineOsc = null
		this.engineGain = null
		this.engineFilter = null
		this.collisionSynth = null
		this.noiseSynth = null
		this.coinSynth = null
		this.lapSynth = null

		this.initialized = false
	}
}

export const racingAudio = new RacingAudioManager()
