// Procedural sprite drawing functions for Pac-Man
// Ported from reference implementation - all sprites drawn via canvas paths

import { Direction } from '../types'

/**
 * Draw ghost sprite
 * @param ctx Canvas context
 * @param x X position (center)
 * @param y Y position (center)
 * @param frame Animation frame (0 or 1)
 * @param dirEnum Direction for eyes
 * @param scared Whether ghost is in frightened mode
 * @param flash Whether to flash white (near end of frightened)
 * @param eyesOnly Whether to draw only eyes (for eaten ghost returning home)
 * @param color Ghost color
 */
export function drawGhostSprite(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number,
	frame: number,
	dirEnum: Direction,
	scared: boolean,
	flash: boolean,
	eyesOnly: boolean,
	color: string
): void {
	ctx.save()
	ctx.translate(x - 7, y - 7)

	const bodyColor = scared ? (flash ? '#FFF' : '#2121ff') : color

	if (!eyesOnly) {
		// Draw body
		ctx.beginPath()
		addHead(ctx)
		if (frame === 0) {
			addFeet1(ctx)
		} else {
			addFeet2(ctx)
		}
		ctx.closePath()
		ctx.lineJoin = 'round'
		ctx.lineCap = 'round'
		ctx.lineWidth = 0.5
		ctx.strokeStyle = bodyColor
		ctx.stroke()
		ctx.lineWidth = 1
		ctx.fillStyle = bodyColor
		ctx.fill()
	}

	// Draw face
	if (scared) {
		addScaredFace(ctx, flash)
	} else {
		addEyes(ctx, dirEnum)
	}

	ctx.restore()
}

/**
 * Add top of ghost head to current path
 */
function addHead(ctx: CanvasRenderingContext2D): void {
	ctx.save()
	ctx.translate(0.5, 0)

	ctx.moveTo(0, 6)
	ctx.quadraticCurveTo(1.5, 0, 6.5, 0)
	ctx.quadraticCurveTo(11.5, 0, 13, 6)

	ctx.restore()
}

/**
 * Add first animation frame feet to path
 */
function addFeet1(ctx: CanvasRenderingContext2D): void {
	const coords = [
		13, 13, 11, 11, 9, 13, 8, 13, 8, 11, 5, 11, 5, 13, 4, 13, 2, 11, 0, 13,
	]

	ctx.save()
	ctx.translate(0.5, 0.5)

	for (let i = 0; i < coords.length; i += 2) {
		ctx.lineTo(coords[i], coords[i + 1])
	}

	ctx.restore()
}

/**
 * Add second animation frame feet to path
 */
function addFeet2(ctx: CanvasRenderingContext2D): void {
	const coords = [
		13, 12, 12, 13, 11, 13, 9, 11, 7, 13, 6, 13, 4, 11, 2, 13, 1, 13, 0, 12,
	]

	ctx.save()
	ctx.translate(0.5, 0.5)

	for (let i = 0; i < coords.length; i += 2) {
		ctx.lineTo(coords[i], coords[i + 1])
	}

	ctx.restore()
}

/**
 * Draw ghost eyes
 */
function addEyes(ctx: CanvasRenderingContext2D, dirEnum: Direction): void {
	ctx.save()
	ctx.translate(2, 3)

	const eyeCoords = [0, 1, 1, 0, 2, 0, 3, 1, 3, 3, 2, 4, 1, 4, 0, 3]

	const drawEyeball = () => {
		ctx.translate(0.5, 0.5)
		ctx.beginPath()
		ctx.moveTo(eyeCoords[0], eyeCoords[1])
		for (let i = 2; i < eyeCoords.length; i += 2) {
			ctx.lineTo(eyeCoords[i], eyeCoords[i + 1])
		}
		ctx.closePath()
		ctx.fill()
		ctx.lineJoin = 'round'
		ctx.stroke()
		ctx.translate(-0.5, -0.5)
	}

	// Translate eyeballs based on direction
	if (dirEnum === Direction.LEFT) ctx.translate(-1, 0)
	else if (dirEnum === Direction.RIGHT) ctx.translate(1, 0)
	else if (dirEnum === Direction.UP) ctx.translate(0, -1)
	else if (dirEnum === Direction.DOWN) ctx.translate(0, 1)

	// Draw eyeballs (white)
	ctx.fillStyle = '#FFF'
	ctx.strokeStyle = '#FFF'
	ctx.lineWidth = 1.0
	ctx.lineJoin = 'round'
	drawEyeball()
	ctx.translate(6, 0)
	drawEyeball()

	// Translate pupils based on direction
	if (dirEnum === Direction.LEFT) ctx.translate(0, 2)
	else if (dirEnum === Direction.RIGHT) ctx.translate(2, 2)
	else if (dirEnum === Direction.UP) ctx.translate(1, 0)
	else if (dirEnum === Direction.DOWN) ctx.translate(1, 3)

	// Draw pupils (blue)
	ctx.fillStyle = '#00F'
	ctx.fillRect(0, 0, 2, 2) // right
	ctx.translate(-6, 0)
	ctx.fillRect(0, 0, 2, 2) // left

	ctx.restore()
}

/**
 * Draw scared ghost face
 */
function addScaredFace(ctx: CanvasRenderingContext2D, flash: boolean): void {
	ctx.strokeStyle = ctx.fillStyle = flash ? '#F00' : '#FF0'

	// Eyes
	ctx.fillRect(4, 5, 2, 2)
	ctx.fillRect(8, 5, 2, 2)

	// Mouth (wavy line)
	const mouthCoords = [
		1, 10, 2, 9, 3, 9, 4, 10, 5, 10, 6, 9, 7, 9, 8, 10, 9, 10, 10, 9, 11, 9, 12,
		10,
	]
	ctx.translate(0.5, 0.5)
	ctx.beginPath()
	ctx.moveTo(mouthCoords[0], mouthCoords[1])
	for (let i = 2; i < mouthCoords.length; i += 2) {
		ctx.lineTo(mouthCoords[i], mouthCoords[i + 1])
	}
	ctx.lineWidth = 1.0
	ctx.stroke()
	ctx.translate(-0.5, -0.5)
}

/**
 * Draw Pac-Man sprite
 * @param ctx Canvas context
 * @param x X position (center)
 * @param y Y position (center)
 * @param dirEnum Direction Pac-Man is facing
 * @param angle Mouth opening angle (radians)
 * @param mouthShift Optional mouth position shift
 * @param scale Optional scale factor
 * @param centerShift Optional center shift
 * @param alpha Optional alpha value
 * @param color Optional override color
 */
export function drawPacmanSprite(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number,
	dirEnum: Direction,
	angle: number,
	mouthShift: number = 0,
	scale: number = 1,
	centerShift: number = 0,
	alpha: number = 1,
	color?: string
): void {
	const bodyColor = color || `rgba(255,255,0,${alpha})`

	ctx.save()
	ctx.translate(x, y)
	ctx.scale(scale, scale)

	// Rotate to current heading direction
	const d90 = Math.PI / 2
	if (dirEnum === Direction.UP) ctx.rotate(3 * d90)
	else if (dirEnum === Direction.RIGHT) ctx.rotate(0)
	else if (dirEnum === Direction.DOWN) ctx.rotate(d90)
	else if (dirEnum === Direction.LEFT) ctx.rotate(2 * d90)

	// Plant corner of mouth
	ctx.beginPath()
	ctx.moveTo(-3 + mouthShift, 0)

	// Draw head outline
	ctx.arc(centerShift, 0, 6.5, angle, 2 * Math.PI - angle)
	ctx.closePath()

	ctx.fillStyle = bodyColor
	ctx.fill()

	ctx.restore()
}

/**
 * Get Pac-Man mouth angle for animation frame
 */
export function getPacmanAngle(frame: number): number {
	switch (frame) {
		case 0:
			return 0 // Closed
		case 1:
			return Math.atan(4 / 5) // Small opening
		case 2:
			return Math.atan(6 / 3) // Wide opening
		default:
			return Math.atan(4 / 5)
	}
}

/**
 * Draw points displayed when eating a ghost
 */
export function drawPacPoints(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number,
	points: number,
	color: string
): void {
	ctx.save()
	ctx.translate(x + 0.5, y + 0.5)
	ctx.translate(0, -1)

	const plotLine = (pts: number[]) => {
		ctx.beginPath()
		ctx.moveTo(pts[0], pts[1])
		for (let i = 2; i < pts.length; i += 2) {
			ctx.lineTo(pts[i], pts[i + 1])
		}
		ctx.lineWidth = 1.0
		ctx.lineCap = ctx.lineJoin = 'round'
		ctx.strokeStyle = color
		ctx.stroke()
	}

	const plotOutline = (pts: number[]) => {
		ctx.beginPath()
		ctx.moveTo(pts[0], pts[1])
		for (let i = 2; i < pts.length; i += 2) {
			ctx.lineTo(pts[i], pts[i + 1])
		}
		ctx.closePath()
		ctx.lineWidth = 1.0
		ctx.lineCap = ctx.lineJoin = 'round'
		ctx.strokeStyle = color
		ctx.stroke()
	}

	const draw0 = (ox: number, oy: number) => {
		ctx.save()
		ctx.translate(ox, oy)
		plotOutline([1, 0, 2, 0, 3, 1, 3, 5, 2, 6, 1, 6, 0, 5, 0, 1])
		ctx.restore()
	}

	const draw2 = (ox: number, oy: number) => {
		ctx.save()
		ctx.translate(ox, oy)
		plotLine([0, 2, 0, 1, 1, 0, 3, 0, 4, 1, 4, 2, 0, 6, 4, 6])
		ctx.restore()
	}

	const draw4 = (ox: number, oy: number) => {
		ctx.save()
		ctx.translate(ox, oy)
		plotLine([3, 6, 3, 0, 0, 3, 0, 4, 4, 4])
		ctx.restore()
	}

	const draw6 = (ox: number, oy: number) => {
		ctx.save()
		ctx.translate(ox, oy)
		plotLine([3, 0, 1, 0, 0, 1, 0, 5, 1, 6, 2, 6, 3, 5, 3, 3, 0, 3])
		ctx.restore()
	}

	const draw8 = (ox: number, oy: number) => {
		ctx.save()
		ctx.translate(ox, oy)
		plotOutline([
			1, 0, 3, 0, 4, 1, 4, 2, 3, 3, 1, 3, 0, 4, 0, 5, 1, 6, 3, 6, 4, 5, 4, 4, 3,
			3, 1, 3, 0, 2, 0, 1,
		])
		ctx.restore()
	}

	// Draw based on point value
	switch (points) {
		case 200:
			draw2(-7, -3)
			draw0(-1, -3)
			draw0(4, -3)
			break
		case 400:
			draw4(-7, -3)
			draw0(-1, -3)
			draw0(4, -3)
			break
		case 800:
			draw8(-7, -3)
			draw0(-1, -3)
			draw0(4, -3)
			break
		case 1600:
			plotLine([-7, -3, -7, 3]) // draw1narrow
			draw6(-5, -3)
			draw0(0, -3)
			draw0(5, -3)
			break
	}

	ctx.restore()
}

/**
 * Draw a fruit sprite by name
 */
export function drawFruitSprite(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number,
	fruitName: string
): void {
	switch (fruitName) {
		case 'cherry':
			drawCherry(ctx, x, y)
			break
		case 'strawberry':
			drawStrawberry(ctx, x, y)
			break
		case 'orange':
			drawOrange(ctx, x, y)
			break
		case 'apple':
			drawApple(ctx, x, y)
			break
		case 'melon':
			drawMelon(ctx, x, y)
			break
		case 'galaxian':
			drawGalaxian(ctx, x, y)
			break
		case 'bell':
			drawBell(ctx, x, y)
			break
		case 'key':
			drawKey(ctx, x, y)
			break
	}
}

function drawCherry(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	const cherry = (cx: number, cy: number) => {
		ctx.save()
		ctx.translate(cx, cy)
		ctx.beginPath()
		ctx.arc(2.5, 2.5, 3, 0, Math.PI * 2)
		ctx.lineWidth = 1.0
		ctx.strokeStyle = '#000'
		ctx.stroke()
		ctx.fillStyle = '#ff0000'
		ctx.fill()
		ctx.lineCap = 'round'
		ctx.beginPath()
		ctx.moveTo(1, 3)
		ctx.lineTo(2, 4)
		ctx.strokeStyle = '#fff'
		ctx.stroke()
		ctx.restore()
	}

	ctx.save()
	ctx.translate(x, y)
	cherry(-6, -1)
	cherry(-1, 1)
	ctx.beginPath()
	ctx.moveTo(-3, 0)
	ctx.bezierCurveTo(-1, -2, 2, -4, 5, -5)
	ctx.lineTo(5, -4)
	ctx.bezierCurveTo(3, -4, 1, 0, 1, 2)
	ctx.strokeStyle = '#ff9900'
	ctx.lineJoin = 'round'
	ctx.lineCap = 'round'
	ctx.stroke()
	ctx.restore()
}

function drawStrawberry(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number
): void {
	ctx.save()
	ctx.translate(x, y)
	// Body
	ctx.beginPath()
	ctx.moveTo(0, -3)
	ctx.lineTo(4, 1)
	ctx.lineTo(3, 5)
	ctx.lineTo(0, 7)
	ctx.lineTo(-3, 5)
	ctx.lineTo(-4, 1)
	ctx.closePath()
	ctx.fillStyle = '#ff0000'
	ctx.fill()
	ctx.strokeStyle = '#000'
	ctx.lineWidth = 0.5
	ctx.stroke()
	// Seeds
	ctx.fillStyle = '#fff'
	ctx.fillRect(-1, 0, 1, 1)
	ctx.fillRect(1, 2, 1, 1)
	ctx.fillRect(-2, 3, 1, 1)
	ctx.fillRect(0, 4, 1, 1)
	// Leaves
	ctx.fillStyle = '#00ff00'
	ctx.fillRect(-2, -4, 1, 2)
	ctx.fillRect(0, -5, 1, 2)
	ctx.fillRect(2, -4, 1, 2)
	ctx.restore()
}

function drawOrange(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	ctx.save()
	ctx.translate(x, y)
	ctx.beginPath()
	ctx.arc(0, 1, 5, 0, Math.PI * 2)
	ctx.fillStyle = '#ffaa00'
	ctx.fill()
	ctx.strokeStyle = '#000'
	ctx.lineWidth = 0.5
	ctx.stroke()
	// Leaf
	ctx.fillStyle = '#00cc00'
	ctx.fillRect(-1, -5, 3, 2)
	// Shine
	ctx.beginPath()
	ctx.arc(-2, -1, 1.5, 0, Math.PI * 2)
	ctx.fillStyle = 'rgba(255,255,255,0.3)'
	ctx.fill()
	ctx.restore()
}

function drawApple(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	ctx.save()
	ctx.translate(x, y)
	ctx.beginPath()
	ctx.arc(0, 1, 5, 0, Math.PI * 2)
	ctx.fillStyle = '#ff0000'
	ctx.fill()
	ctx.strokeStyle = '#000'
	ctx.lineWidth = 0.5
	ctx.stroke()
	// Stem
	ctx.beginPath()
	ctx.moveTo(0, -4)
	ctx.lineTo(1, -6)
	ctx.strokeStyle = '#964B00'
	ctx.lineWidth = 1
	ctx.stroke()
	// Leaf
	ctx.fillStyle = '#00cc00'
	ctx.fillRect(1, -6, 2, 1)
	// Shine
	ctx.beginPath()
	ctx.arc(-2, -1, 1.5, 0, Math.PI * 2)
	ctx.fillStyle = 'rgba(255,255,255,0.3)'
	ctx.fill()
	ctx.restore()
}

function drawMelon(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	ctx.save()
	ctx.translate(x, y)
	ctx.beginPath()
	ctx.arc(0, 1, 5.5, 0, Math.PI * 2)
	ctx.fillStyle = '#00cc00'
	ctx.fill()
	ctx.strokeStyle = '#000'
	ctx.lineWidth = 0.5
	ctx.stroke()
	// Stripes
	ctx.strokeStyle = '#006600'
	ctx.lineWidth = 1
	ctx.beginPath()
	ctx.moveTo(-2, -3)
	ctx.lineTo(-2, 5)
	ctx.stroke()
	ctx.beginPath()
	ctx.moveTo(2, -3)
	ctx.lineTo(2, 5)
	ctx.stroke()
	ctx.restore()
}

function drawGalaxian(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number
): void {
	ctx.save()
	ctx.translate(x, y)
	// Ship body
	ctx.beginPath()
	ctx.moveTo(0, -5)
	ctx.lineTo(4, 2)
	ctx.lineTo(2, 1)
	ctx.lineTo(2, 4)
	ctx.lineTo(-2, 4)
	ctx.lineTo(-2, 1)
	ctx.lineTo(-4, 2)
	ctx.closePath()
	ctx.fillStyle = '#ffff00'
	ctx.fill()
	// Blue center
	ctx.fillStyle = '#0000ff'
	ctx.fillRect(-1, -1, 2, 3)
	// Red tip
	ctx.fillStyle = '#ff0000'
	ctx.fillRect(-1, -3, 2, 2)
	ctx.restore()
}

function drawBell(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	ctx.save()
	ctx.translate(x, y)
	// Bell body
	ctx.beginPath()
	ctx.moveTo(-1, -5)
	ctx.lineTo(1, -5)
	ctx.lineTo(2, -3)
	ctx.lineTo(3, 0)
	ctx.lineTo(4, 3)
	ctx.lineTo(5, 5)
	ctx.lineTo(-5, 5)
	ctx.lineTo(-4, 3)
	ctx.lineTo(-3, 0)
	ctx.lineTo(-2, -3)
	ctx.closePath()
	ctx.fillStyle = '#ffff00'
	ctx.fill()
	ctx.strokeStyle = '#000'
	ctx.lineWidth = 0.5
	ctx.stroke()
	// Clapper
	ctx.beginPath()
	ctx.arc(0, 6, 1.5, 0, Math.PI * 2)
	ctx.fillStyle = '#ccaa00'
	ctx.fill()
	ctx.restore()
}

function drawKey(ctx: CanvasRenderingContext2D, x: number, y: number): void {
	ctx.save()
	ctx.translate(x, y)
	// Key head (ring)
	ctx.beginPath()
	ctx.arc(0, -3, 3, 0, Math.PI * 2)
	ctx.strokeStyle = '#00ccff'
	ctx.lineWidth = 1.5
	ctx.stroke()
	// Key shaft
	ctx.beginPath()
	ctx.moveTo(0, 0)
	ctx.lineTo(0, 6)
	ctx.strokeStyle = '#00ccff'
	ctx.lineWidth = 1.5
	ctx.stroke()
	// Key teeth
	ctx.beginPath()
	ctx.moveTo(0, 4)
	ctx.lineTo(2, 4)
	ctx.moveTo(0, 6)
	ctx.lineTo(2, 6)
	ctx.strokeStyle = '#00ccff'
	ctx.lineWidth = 1
	ctx.stroke()
	ctx.restore()
}

/**
 * Draw fruit score text
 */
export function drawFruitScore(
	ctx: CanvasRenderingContext2D,
	x: number,
	y: number,
	points: number
): void {
	ctx.save()
	ctx.translate(x, y)
	ctx.fillStyle = '#FFC0CB'
	ctx.font = 'bold 7px monospace'
	ctx.textAlign = 'center'
	ctx.textBaseline = 'middle'
	ctx.fillText(String(points), 0, 0)
	ctx.restore()
}
